const crypto = global.get('crypto');
function hashPassword(p, s) { return crypto.createHash('sha256').update(p + s).digest('hex'); }
if (!global.get('dcim_users')) {
    const aS = crypto.randomBytes(16).toString('hex');
    const tS = crypto.randomBytes(16).toString('hex');
    global.set('dcim_users', {
        'admin': { username:'admin', displayName:'System Administrator', role:'ADMIN', salt:aS, passwordHash:hashPassword('Admin@DCIM2024!',aS), failedAttempts:0 },
        'technician': { username:'technician', displayName:'DC Technician', role:'USER', salt:tS, passwordHash:hashPassword('Tech@DCIM2024!',tS), failedAttempts:0 }
    });
    node.warn('✅ Users initialized');
}
if (!global.get('dcim_sessions')) global.set('dcim_sessions', {});
if (!global.get('audit_log')) global.set('audit_log', []);
if (!global.get('cooling_thresholds')) global.set('cooling_thresholds', { inletTempWarning:24.0, inletTempCritical:27.0, humidityLow:30, humidityHigh:65 });
msg.payload = { status:'initialized' };
