const crypto = global.get('crypto');
const body = msg.payload;
if (!body || !body.username || !body.password) { msg.statusCode=400; msg.payload={success:false,error:'Username and password required'}; return msg; }
const users = global.get('dcim_users') || {};
const user = users[body.username.toLowerCase()];
const auditLog = global.get('audit_log') || [];
if (!user) {
    auditLog.unshift({timestamp:new Date().toISOString(),event:'LOGIN_FAILED',username:body.username,ip:msg.req.ip||'unknown',reason:'User not found'});
    global.set('audit_log',auditLog);
    msg.statusCode=401; msg.payload={success:false,error:'Invalid credentials'}; return msg;
}
if (user.lockedUntil && Date.now()<user.lockedUntil) {
    msg.statusCode=423; msg.payload={success:false,error:`Account locked. Try again in ${Math.ceil((user.lockedUntil-Date.now())/60000)} minutes.`}; return msg;
}
const hash = crypto.createHash('sha256').update(body.password+user.salt).digest('hex');
if (hash !== user.passwordHash) {
    user.failedAttempts=(user.failedAttempts||0)+1;
    if (user.failedAttempts>=5) user.lockedUntil=Date.now()+(15*60*1000);
    users[body.username.toLowerCase()]=user;
    global.set('dcim_users',users);
    auditLog.unshift({timestamp:new Date().toISOString(),event:'LOGIN_FAILED',username:body.username,ip:msg.req.ip||'unknown',reason:'Wrong password'});
    global.set('audit_log',auditLog);
    msg.statusCode=401; msg.payload={success:false,error:'Invalid credentials'}; return msg;
}
user.failedAttempts=0; user.lockedUntil=null;
users[body.username.toLowerCase()]=user;
global.set('dcim_users',users);
const token=crypto.randomBytes(32).toString('hex');
const session={token,username:user.username,role:user.role,displayName:user.displayName,createdAt:Date.now(),expiresAt:Date.now()+(15*60*1000),lastActivity:Date.now(),ip:msg.req.ip||'unknown'};
const sessions=global.get('dcim_sessions')||{};
sessions[token]=session;
global.set('dcim_sessions',sessions);
auditLog.unshift({timestamp:new Date().toISOString(),event:'LOGIN_SUCCESS',username:user.username,role:user.role,ip:msg.req.ip||'unknown'});
if (auditLog.length>500) auditLog.pop();
global.set('audit_log',auditLog);
msg.statusCode=200; msg.payload={success:true,token,role:user.role,displayName:user.displayName,expiresAt:session.expiresAt};
return msg;

const token=msg.req.headers['x-auth-token']||(msg.payload&&msg.payload.token);
if (token) {
    const sessions=global.get('dcim_sessions')||{};
    const session=sessions[token];
    if (session) {
        const auditLog=global.get('audit_log')||[];
        auditLog.unshift({timestamp:new Date().toISOString(),event:'LOGOUT',username:session.username,ip:msg.req.ip||'unknown'});
        global.set('audit_log',auditLog);
        delete sessions[token];
        global.set('dcim_sessions',sessions);
    }
}
msg.statusCode=200; msg.payload={success:true};
return msg;

const token=msg.req.headers['x-auth-token'];
const sessions=global.get('dcim_sessions')||{};
const session=sessions[token];
if (!session||Date.now()>session.expiresAt) { msg.statusCode=401; msg.payload={error:'Authentication required'}; return msg; }
session.expiresAt=Date.now()+(15*60*1000);
session.lastActivity=Date.now();
sessions[token]=session;
global.set('dcim_sessions',sessions);
const power=global.get('power_state')||{};
const cooling=global.get('cooling_state')||{};
const safety=global.get('safety_state')||{};
const allAlerts=[...(global.get('power_alerts')||[]),...(global.get('cooling_alerts')||[]),...(global.get('safety_alerts')||[])];
