msg.statusCode=200;
msg.payload={meta:{collectedAt:new Date().toISOString(),requestedBy:session.username,role:session.role,healthStatus,alertSummary:{critical:criticalCount,warning:warningCount,total:allAlerts.length}},power,cooling,safety,alerts:allAlerts,auditLog:session.role==='ADMIN'?(global.get('audit_log')||[]).slice(0,20):undefined};
return msg;

const token=msg.req.headers['x-auth-token'];
const sessions=global.get('dcim_sessions')||{};
