msg.payload={success:true,message:`${msg.payload.device} ${msg.payload.action} by ${session.username}`,timestamp:new Date().toISOString()};
return msg;

const fs = global.get('fs');
try {
    msg.payload = fs.readFileSync('/data/dashboard.html', 'utf8');
    msg.headers = {'Content-Type': 'text/html'};
    msg.statusCode = 200;
} catch(e) {
    msg.payload = 'Error: ' + e.message;
