const prev=global.get('power_state')||{itLoad:45.0,upsStatus:'On_Mains',batteryCapacity:98.5,tick:0};
const tick=prev.tick+1;
let upsStatus=prev.upsStatus;
const roll=Math.random();
if (roll>0.998) upsStatus=upsStatus==='On_Mains'?'On_Battery':'On_Mains';
else if (roll>0.9995&&upsStatus==='On_Mains') upsStatus='On_Bypass';
const timeOfDay=(Date.now()/3600000)%24;
const noise=(Math.random()-0.5)*0.8;
const itLoad=Math.max(35,Math.min(60,prev.itLoad+noise));
let batteryCapacity=prev.batteryCapacity;
if (upsStatus==='On_Battery') batteryCapacity=Math.max(0,batteryCapacity-0.5);
else batteryCapacity=Math.min(100,batteryCapacity+0.1);
const pduA=itLoad*0.51+(Math.random()-0.5)*0.3;
const pduB=itLoad*0.49+(Math.random()-0.5)*0.3;
const coolingPower=itLoad*0.38+2.5;
const totalFacilityPower=itLoad+coolingPower+3.2;
const pue=totalFacilityPower/itLoad;
const upsLoadPercent=Math.round((itLoad/80)*100);
const state={itLoad:parseFloat(itLoad.toFixed(2)),totalFacilityPower:parseFloat(totalFacilityPower.toFixed(2)),coolingPower:parseFloat(coolingPower.toFixed(2)),upsStatus,batteryCapacity:parseFloat(batteryCapacity.toFixed(1)),upsLoadPercent,pduA_kW:parseFloat(pduA.toFixed(2)),pduB_kW:parseFloat(pduB.toFixed(2)),pue:parseFloat(pue.toFixed(3)),pueRating:pue<1.2?'EXCELLENT':pue<1.5?'GOOD':pue<1.8?'AVERAGE':'POOR',timestamp:new Date().toISOString(),tick};
global.set('power_state',state);
const alerts=[];
if (upsStatus==='On_Battery') alerts.push({level:'CRITICAL',code:'UPS_ON_BATTERY',message:`UPS on battery! ${batteryCapacity}%`});
if (batteryCapacity<20) alerts.push({level:'CRITICAL',code:'LOW_BATTERY',message:`Low battery: ${batteryCapacity}%`});
if (pue>2.0) alerts.push({level:'WARNING',code:'HIGH_PUE',message:`PUE ${pue} exceeds target`});
global.set('power_alerts',alerts);
msg.payload=state; msg.topic='power'; return msg;

const prev=global.get('cooling_state')||{inletTemp:22.5,humidity:45.0,crac1Status:'RUNNING',crac2Status:'STANDBY',tick:0};
const tick=prev.tick+1;
const itLoad=(global.get('power_state')||{itLoad:45}).itLoad;
const loadFactor=(itLoad-35)/25;
let crac1Status=prev.crac1Status;
let crac2Status=prev.crac2Status;
if (prev.inletTemp>24.0&&crac2Status==='STANDBY') crac2Status='RUNNING';
else if (prev.inletTemp<22.0&&crac2Status==='RUNNING') crac2Status='STANDBY';
const cracCorrection=crac1Status==='RUNNING'?-0.15:0;
const crac2Correction=crac2Status==='RUNNING'?-0.1:0;
const inletTemp=Math.max(18,Math.min(35,prev.inletTemp+loadFactor*0.08+cracCorrection+crac2Correction+(Math.random()-0.5)*0.05));
const hotColdAisleDelta=10+loadFactor*8;
const returnTemp=inletTemp+hotColdAisleDelta;
const humidity=Math.max(30,Math.min(70,prev.humidity+(Math.random()-0.5)*0.3));
const state={inletTemp:parseFloat(inletTemp.toFixed(2)),returnTemp:parseFloat(returnTemp.toFixed(2)),hotColdAisleDelta:parseFloat(hotColdAisleDelta.toFixed(1)),humidity:parseFloat(humidity.toFixed(1)),crac1Status,crac2Status,ashrae_compliant:inletTemp>=15&&inletTemp<=27,ashrae_class:inletTemp<=27?'A1/A2':inletTemp<=35?'A3':'EXCEEDED',timestamp:new Date().toISOString(),tick};
global.set('cooling_state',state);
const th=global.get('cooling_thresholds')||{inletTempWarning:24.0,inletTempCritical:27.0,humidityLow:30,humidityHigh:65};
const alerts=[];
if (inletTemp>=th.inletTempCritical) alerts.push({level:'CRITICAL',code:'TEMP_CRITICAL',message:`Inlet CRITICAL: ${inletTemp}°C`});
else if (inletTemp>=th.inletTempWarning) alerts.push({level:'WARNING',code:'TEMP_WARNING',message:`Inlet elevated: ${inletTemp}°C`});
if (humidity<th.humidityLow) alerts.push({level:'WARNING',code:'HUMIDITY_LOW',message:`Humidity low: ${humidity}%RH`});
if (humidity>th.humidityHigh) alerts.push({level:'WARNING',code:'HUMIDITY_HIGH',message:`Humidity high: ${humidity}%RH`});
global.set('cooling_alerts',alerts);
msg.payload=state; msg.topic='cooling'; return msg;

const prev=global.get('safety_state')||{rackDoor:{},tick:0};
const tick=prev.tick+1;
const waterLeak=Math.random()>0.999;
const smokeDetector=Math.random()>0.9995;
